// ❌ Error
let x = 1;
let x = 2;  // already declared

// ✅ Fix
let x = 1;
x = 2;      // just reassign

// ❌ Infinite recursion
function loop() { loop(); }

// ✅ Fix - add base case
function countdown(n) {
  if (n <= 0) return;
  countdown(n - 1);
}

// ❌ Error: 'this' is undefined in callback
class Counter {
  constructor() { this.count = 0; }
  start() {
    setInterval(function() { this.count++; }, 1000);
  }
}

// ✅ Fix: arrow function preserves 'this'
class Counter {
  constructor() { this.count = 0; }
  start() {
    setInterval(() => { this.count++; }, 1000);
  }
}

// ❌ Error
import myModule from 'myModule';  // No such package

// ✅ Fix
npm install myModule
import myModule from 'myModule';

// ❌ Conditional hook call
function MyComp({ show }) {
  if (show) {
    useEffect(() => {}, []);  // Error!
  }
}

// ✅ Fix
function MyComp({ show }) {
  useEffect(() => {
    if (show) { /* do something */ }
  }, [show]);
}

// ❌ Infinite loop!
const [count, setCount] = useState(0);
useEffect(() => {
  setCount(count + 1);  // updates count, triggers re-run
}, [count]);

// ✅ Fix - functional update
useEffect(() => {
  setCount(c => c + 1);  // No dependency needed!
}, []);

// ❌ Error
interface User { name: string; age: number; }
const u: User = { name: 'Alice' };  // missing 'age'

// ✅ Fix
interface User { name: string; age?: number; }  // age is optional
const u: User = { name: 'Alice' };
